double demanderinclinaison(double b){            // demander dans quel sens le joueur va incliner la carte poussante
    double a=0;
    int c=0;
    if (b==5 || b==6){
        printf("Voulez vous incliner la pi%cce de 90%c ou 180%c\n",138,423,423);
        scanf("%d",&c);
        if (c==90 && b==5){
            a=6;
        }
        else if (c==90 && b==6){
            a=5;
        }
        else if (c==180){
            a=b;
        }
    }
    else {
        printf("De quelle inclinaison voulez vous tournez la carte poussante : 90%c - 180%c - 270%c - 360%c ?\n",423,423,423,423);
        scanf("%d",&c);
        if (b>1 && b<2){
            if (c==90){
                a=b+3;
            }
            if (c==180){
                a=b+1;
            }
            if (c==270){
                a=b+2;
            }
            if (c==360){
                a=b;
            }
        }
        if (b>2 && b<3){
            if (c==90){
                a=b+1;
            }
            if (c==180){
                a=b-1;
            }
            if (c==270){
                a=b+2;
            }
            if (c==360){
                a=b;
            }
        }
        if (b>3 && b<4){
            if (c==90){
                a=b-2;
            }
            if (c==180){
                a=b+1;
            }
            if (c==270){
                a=b-1;
            }
            if (c==360) {
                a=b;
            }
        }
        if (b>4 && b<5){
            if (c==90){
                a=b-2;
            }
            if (c==180){
                a=b-1;
            }
            if (c==270){
                a=b-3;
            }
            if (c==360) {
                a=b;
            }
        }
        if (b>=7 && b<8){
            if (c==90){
                a=b+2;
            }
            if (c==180){
                a=b+3;
            }
            if (c==270){
                a=b+1;
            }
            if (c==360) {
                a=b;
            }
        }
        if (b>=8 && b<9){
            if (c==90){
                a=b-1;
            }
            if (c==180){
                a=b+1;
            }
            if (c==270){
                a=b+2;
            }
            if (c==360) {
                a=b;
            }
        }
        if (b>=9 && b<10){
            if (c==90){
                a=b+1;
            }
            if (c==180){
                a=b-1;
            }
            if (c==270){
                a=b-2;
            }
            if (c==360) {
                a=b;
            }
        }
        if (b>=10 && b<11){
            if (c==90){
                a=b-2;
            }
            if (c==180){
                a=b-3;
            }
            if (c==270){
                a=b-1;
            }
            if (c==360) {
                a=b;
            }
        }
    }
    return a;
}








